const body = $input.first().json.body || $input.first().json;
const message = (body.message || '').trim();
const userId = body.userId || ('anon-' + Date.now());
const channel = body.channel || 'web';
const intent = body.intent || 'triage_intro';
const phqScore = Number(body.phqScore) || 0;
const gadScore = Number(body.gadScore) || 0;
const userContext = body.userContext || message;
const riskLevel = body.riskLevel || 'moderate';
const CRISIS_KEYWORDS = ['suicide','kill myself','end my life','want to die',"can't go on",'cant go on','no point living','self harm','hurt myself','overdose','not worth living','ending it'];
const isCrisis = CRISIS_KEYWORDS.some(kw => message.toLowerCase().includes(kw));
return [{ json: { userId, message, channel, intent, phqScore, gadScore, userContext, riskLevel, isCrisis, timestamp: new Date().toISOString() } }];

const riskRaw = $('Risk Agent').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let riskData = {};
try { riskData = JSON.parse(riskRaw.replace(/```json|```/g, '').trim()); } catch(e) { const total = $('Parse & Crisis Check').first().json.phqScore + $('Parse & Crisis Check').first().json.gadScore; const lvl = total <= 2 ? 'low' : total <= 5 ? 'moderate' : 'high'; riskData = { riskLevel: lvl, riskTitle: lvl === 'low' ? 'Coping Well' : lvl === 'moderate' ? 'Some Signs of Distress' : 'Please Seek Support', riskIcon: lvl === 'low' ? '🌱' : lvl === 'moderate' ? '🌤️' : '⚡', personalMessage: 'Your responses have been recorded. Please follow the recommended next steps.', keyInsight: '' }; }
const stepsRaw = $('CareNavigator Agent').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
let steps = [];
try { const parsed = JSON.parse(stepsRaw.replace(/```json|```/g, '').trim()); steps = Array.isArray(parsed) ? parsed : []; } catch(e) { steps = []; }
while (steps.length < 3) { steps.push('Continue monitoring your wellbeing and reach out to a healthcare provider if needed'); }
return [{ json: { intent: 'analyse_results', riskLevel: riskData.riskLevel || 'moderate', riskTitle: riskData.riskTitle || 'Check In With Someone', riskIcon: riskData.riskIcon || '🌤️', personalMessage: riskData.personalMessage || '', keyInsight: riskData.keyInsight || '', nextSteps: steps.slice(0, 3), phqScore: $('Parse & Crisis Check').first().json.phqScore, gadScore: $('Parse & Crisis Check').first().json.gadScore, screeningComplete: true, timestamp: new Date().toISOString() } }];

const data = $input.first().json;
const parsed = $('Parse & Crisis Check').first().json;
const record = { anonymousId: parsed.userId, riskLevel: data.riskLevel || 'unknown', phqScore: data.phqScore || 0, gadScore: data.gadScore || 0, channel: parsed.channel, followUpDue: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(), timestamp: new Date().toISOString() };
console.log('SCREENING STORED:', JSON.stringify(record));
return [{ json: { ...data, stored: true, followUpScheduled: true } }];

const parsed = $('Parse & Crisis Check').first().json;
const record = { anonymousId: parsed.userId, eventType: 'crisis_detected', channel: parsed.channel, timestamp: new Date().toISOString() };
console.log('CRISIS EVENT LOGGED:', JSON.stringify(record));
return [{ json: { ...$input.first().json, crisisLogged: true } }];

const text = $('FollowUp Agent').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || 'Hi, just checking in — how have you been feeling since your last MindBridge screening? We are here for you whenever you are ready. 🌿';
const patient = $('Fetch Patients Due').first().json;
console.log('FOLLOW-UP QUEUED:', { userId: patient.userId, message: text });
return [{ json: { userId: patient.userId, lastRisk: patient.lastRisk, followUpMessage: text, status: 'queued', deliveryChannel: patient.channel || 'web', scheduledAt: new Date().toISOString() } }];

return [
  { json: { userId: 'anon-001', daysSince: 7,  lastRisk: 'moderate', channel: 'web' } },
  { json: { userId: 'anon-002', daysSince: 7,  lastRisk: 'high',     channel: 'web' } },
  { json: { userId: 'anon-003', daysSince: 30, lastRisk: 'low',      channel: 'web' } }
];
